diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..6cb33e77f920 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2025,10 +2025,25 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
         return R;

     Constant *C2;
-
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C - ((C2 - X) & Mask) --> X & Mask
+    // if C == C2 & Mask and the sub C2-X has NUW.
+    {
+      const APInt *MaskC, *C2Int, *CInt;
+      if (match(Op1, m_And(m_OneUse(m_Sub(m_APInt(C2Int), m_Value(X))),
+                           m_APInt(MaskC))) &&
+          match(Op0, m_APInt(CInt)) && *CInt == (*C2Int & *MaskC)) {
+        // Re-find the sub instruction to check NUW flag
+        Value *SubOp = cast<BinaryOperator>(Op1)->getOperand(0);
+        if (auto *SI = dyn_cast<BinaryOperator>(SubOp))
+          if (SI->getOpcode() == Instruction::Sub && SI->hasNoUnsignedWrap())
+            return BinaryOperator::CreateAnd(
+                X, ConstantInt::get(I.getType(), *MaskC));
+      }
+    }
   }

   const APInt *Op0C;

